231: void ConnPoolImplBase::attachStreamToClient(Envoy::ConnectionPool::ActiveClient& client,
232:                                             AttachContext& context) {
233:   ASSERT(client.readyForStream(), dumpState());
234: 
235:   Upstream::ClusterTrafficStats& traffic_stats = *host_->cluster().trafficStats();
236:   if (client.state() == Envoy::ConnectionPool::ActiveClient::State::ReadyForEarlyData) {
237:     traffic_stats.upstream_rq_0rtt_.inc();
238:   }
239: 
240:   if (enforceMaxRequests() && !host_->cluster().resourceManager(priority_).requests().canCreate()) {
241:     ENVOY_LOG(debug, "max streams overflow");
242:     onPoolFailure(client.real_host_description_, absl::string_view(),
243:                   ConnectionPool::PoolFailureReason::Overflow, context);
244:     traffic_stats.upstream_rq_pending_overflow_.inc();
245:     return;
246:   }
247:   ENVOY_CONN_LOG(debug, "creating stream", client);
248: 
249:   // Latch capacity before updating remaining streams.
250:   uint64_t capacity = client.currentUnusedCapacity();
251:   client.remaining_streams_--;
252:   if (client.remaining_streams_ == 0) {
253:     ENVOY_CONN_LOG(debug, "maximum streams per connection, start draining", client);
254:     traffic_stats.upstream_cx_max_requests_.inc();
255:     transitionActiveClientState(client, Envoy::ConnectionPool::ActiveClient::State::Draining);
256:   } else if (capacity == 1) {
257:     // As soon as the new stream is created, the client will be maxed out.
258:     transitionActiveClientState(client, Envoy::ConnectionPool::ActiveClient::State::Busy);
259:   }
260: 
261:   // Decrement the capacity, as there's one less stream available for serving.
262:   // For HTTP/3, the capacity is updated in newStreamEncoder.
263:   if (trackStreamCapacity()) {
264:     decrConnectingAndConnectedStreamCapacity(1, client);
265:   }
266:   // Track the new active stream.
267:   cluster_connectivity_state_.incrActiveStreams(1);
268:   num_active_streams_++;
269:   host_->stats().rq_total_.inc();
270:   host_->stats().rq_active_.inc();
271:   traffic_stats.upstream_rq_total_.inc();
272:   traffic_stats.upstream_rq_active_.inc();
273:   host_->cluster().resourceManager(priority_).requests().inc();
274: 
275:   onPoolReady(client, context);
276: }
277: 
278: void ConnPoolImplBase::onStreamClosed(Envoy::ConnectionPool::ActiveClient& client,
279:                                       bool delay_attaching_stream) {
280:   ENVOY_CONN_LOG(
281:       debug, "destroying stream: {} active remaining, readyForStream {}, currentUnusedCapacity {}",
282:       client, client.numActiveStreams(), client.readyForStream(), client.currentUnusedCapacity());
283:   ASSERT(num_active_streams_ > 0, dumpState());
284:   cluster_connectivity_state_.decrActiveStreams(1);
285:   num_active_streams_--;
286:   host_->stats().rq_active_.dec();
287:   host_->cluster().trafficStats()->upstream_rq_active_.dec();
288:   host_->cluster().resourceManager(priority_).requests().dec();
289:   // We don't update the capacity for HTTP/3 as the stream count should only
290:   // increase when a MAX_STREAMS frame is received.
291:   if (trackStreamCapacity()) {
292:     // If the effective client capacity was limited by concurrency, increase connected capacity.
293:     bool limited_by_concurrency =
294:         client.remaining_streams_ > client.concurrent_stream_limit_ - client.numActiveStreams() - 1;
295:     // The capacity calculated by concurrency could be negative if a SETTINGS frame lowered the
296:     // number of allowed streams. In this case, connecting_and_connected_stream_capacity_ can be
297:     // negative, and effective client capacity was still limited by concurrency. Compare
298:     // client.concurrent_stream_limit_ and client.numActiveStreams() directly to avoid overflow.
299:     bool negative_capacity = client.concurrent_stream_limit_ < client.numActiveStreams() + 1;
300:     if (negative_capacity || limited_by_concurrency) {
301:       incrConnectingAndConnectedStreamCapacity(1, client);
302:     }
303:   }
304:   if (client.state() == ActiveClient::State::Draining && client.numActiveStreams() == 0) {
305:     // Close out the draining client if we no longer have active streams.
306:     client.close();
307:   } else if (client.state() == ActiveClient::State::Busy && client.currentUnusedCapacity() > 0) {
308:     if (!client.hasHandshakeCompleted()) {
309:       transitionActiveClientState(client, ActiveClient::State::ReadyForEarlyData);
310:       if (!delay_attaching_stream) {
311:         onUpstreamReadyForEarlyData(client);
312:       }
313:     } else {
314:       transitionActiveClientState(client, ActiveClient::State::Ready);
315:       if (!delay_attaching_stream) {
316:         onUpstreamReady();
317:       }
318:     }
319:   }
320: }
