322: ConnectionPool::Cancellable* ConnPoolImplBase::newStreamImpl(AttachContext& context,
323:                                                              bool can_send_early_data) {
324:   ASSERT(!is_draining_for_deletion_, dumpState());
325:   ASSERT(!deferred_deleting_, dumpState());
326:   assertCapacityCountsAreCorrect();
327: 
328:   if (!ready_clients_.empty()) {
329:     ActiveClient& client = *ready_clients_.front();
330:     ENVOY_CONN_LOG(debug, "using existing fully connected connection", client);
331:     attachStreamToClient(client, context);
332:     // Even if there's a ready client, we may want to preconnect to handle the next incoming stream.
333:     tryCreateNewConnections();
334:     return nullptr;
335:   }
336: 
337:   if (can_send_early_data && !early_data_clients_.empty()) {
338:     ActiveClient& client = *early_data_clients_.front();
339:     ENVOY_CONN_LOG(debug, "using existing early data ready connection", client);
340:     attachStreamToClient(client, context);
341:     // Even if there's an available client, we may want to preconnect to handle the next
342:     // incoming stream.
343:     tryCreateNewConnections();
344:     return nullptr;
345:   }
346: 
347:   if (!host_->cluster().resourceManager(priority_).pendingRequests().canCreate()) {
348:     ENVOY_LOG(debug, "max pending streams overflow");
349:     onPoolFailure(nullptr, absl::string_view(), ConnectionPool::PoolFailureReason::Overflow,
350:                   context);
351:     host_->cluster().trafficStats()->upstream_rq_pending_overflow_.inc();
352:     return nullptr;
353:   }
354: 
355:   ConnectionPool::Cancellable* pending = newPendingStream(context, can_send_early_data);
356:   ENVOY_LOG(debug, "trying to create new connection");
357:   ENVOY_LOG(trace, fmt::format("{}", *this));
358: 
359:   auto old_capacity = connecting_stream_capacity_;
360:   // This must come after newPendingStream() because this function uses the
361:   // length of pending_streams_ to determine if a new connection is needed.
362:   const ConnectionResult result = tryCreateNewConnections();
363:   // If there is not enough connecting capacity, the only reason to not
364:   // increase capacity is if the connection limits are exceeded or load shed is
365:   // triggered.
366:   ENVOY_BUG(pending_streams_.size() <= connecting_stream_capacity_ ||
367:                 connecting_stream_capacity_ > old_capacity ||
368:                 (result == ConnectionResult::NoConnectionRateLimited ||
369:                  result == ConnectionResult::FailedToCreateConnection ||
370:                  result == ConnectionResult::LoadShed),
371:             fmt::format("Failed to create expected connection: {}", *this));
372:   if (result == ConnectionResult::FailedToCreateConnection) {
373:     // This currently only happens for HTTP/3 if secrets aren't yet loaded.
374:     // Trigger connection failure.
375:     pending->cancel(Envoy::ConnectionPool::CancelPolicy::CloseExcess);
376:     onPoolFailure(nullptr, absl::string_view(),
377:                   ConnectionPool::PoolFailureReason::LocalConnectionFailure, context);
378:     return nullptr;
379:   } else if (result == ConnectionResult::LoadShed) {
380:     pending->cancel(Envoy::ConnectionPool::CancelPolicy::CloseExcess);
381:     onPoolFailure(nullptr, absl::string_view(), ConnectionPool::PoolFailureReason::Overflow,
382:                   context);
383:     return nullptr;
384:   }
385:   return pending;
386: }
