388: bool ConnPoolImplBase::maybePreconnectImpl(float global_preconnect_ratio) {
389:   ASSERT(!deferred_deleting_, dumpState());
390:   return tryCreateNewConnection(global_preconnect_ratio) == ConnectionResult::CreatedNewConnection;
