29: // ActiveClient provides a base class for connection pool clients that handles connection timings
30: // as well as managing the connection timeout.
31: class ActiveClient : public LinkedObject<ActiveClient>,
32:                      public Network::ConnectionCallbacks,
33:                      public Event::DeferredDeletable,
34:                      protected Logger::Loggable<Logger::Id::pool> {
35: public:
36:   ActiveClient(ConnPoolImplBase& parent, uint32_t lifetime_stream_limit,
37:                uint32_t effective_concurrent_streams, uint32_t concurrent_stream_limit);
38:   ActiveClient(ConnPoolImplBase& parent, uint32_t lifetime_stream_limit,
39:                uint32_t concurrent_stream_limit);
40:   ~ActiveClient() override;
41: 
42:   virtual void releaseResources() { releaseResourcesBase(); }
43:   void releaseResourcesBase();
44: 
45:   // Network::ConnectionCallbacks
46:   void onAboveWriteBufferHighWatermark() override {}
47:   void onBelowWriteBufferLowWatermark() override {}
48: 
49:   // Called if the connection does not complete within the cluster's connectTimeout()
50:   void onConnectTimeout();
51: 
52:   // Called if the maximum connection duration is reached.
53:   void onConnectionDurationTimeout();
54: 
55:   // Returns the concurrent stream limit, accounting for if the total stream limit
56:   // is less than the concurrent stream limit.
57:   virtual uint32_t effectiveConcurrentStreamLimit() const {
58:     return std::min(remaining_streams_, concurrent_stream_limit_);
59:   }
60: 
61:   // Returns the application protocol, or absl::nullopt for TCP.
62:   virtual absl::optional<Http::Protocol> protocol() const PURE;
63: 
64:   virtual int64_t currentUnusedCapacity() const {
65:     int64_t remaining_concurrent_streams =
66:         static_cast<int64_t>(concurrent_stream_limit_) - numActiveStreams();
67: 
68:     return std::min<int64_t>(remaining_streams_, remaining_concurrent_streams);
69:   }
70: 
71:   // Initialize upstream read filters. Called when connected.
72:   virtual void initializeReadFilters() PURE;
73: 
74:   // Closes the underlying connection.
75:   virtual void
76:   close(Envoy::Network::ConnectionCloseType type = Envoy::Network::ConnectionCloseType::NoFlush,
77:         absl::string_view details = "") PURE;
78:   // Returns the ID of the underlying connection.
79:   virtual uint64_t id() const PURE;
80:   // Returns true if this closed with an incomplete stream, for stats tracking/ purposes.
81:   virtual bool closingWithIncompleteStream() const PURE;
82:   // Returns the number of active streams on this connection.
83:   virtual uint32_t numActiveStreams() const PURE;
84: 
85:   // Return true if it is ready to dispatch the next stream.
86:   virtual bool readyForStream() const {
87:     ASSERT(!supportsEarlyData());
88:     return state_ == State::Ready;
89:   }
90: 
91:   enum class State {
92:     Connecting,        // Connection is not yet established.
93:     ReadyForEarlyData, // Any additional early data stream can be immediately dispatched to this
94:                        // connection.
95:     Ready,             // Additional streams may be immediately dispatched to this connection.
96:     Busy,              // Connection is at its concurrent stream limit.
97:     Draining,          // No more streams can be dispatched to this connection, and it will be
98:                        // closed when all streams complete.
99:     Closed             // Connection is closed and object is queued for destruction.
100:   };
