14: ActiveTcpClient::ActiveTcpClient(Envoy::ConnectionPool::ConnPoolImplBase& parent,
15:                                  const Upstream::HostConstSharedPtr& host,
16:                                  uint32_t concurrent_stream_limit,
17:                                  absl::optional<std::chrono::milliseconds> idle_timeout)
18:     : Envoy::ConnectionPool::ActiveClient(parent, host->cluster().maxRequestsPerConnection(),
19:                                           concurrent_stream_limit),
20:       parent_(parent), idle_timeout_(idle_timeout) {
21:   Upstream::Host::CreateConnectionData data = host->createConnection(
22:       parent_.dispatcher(), parent_.socketOptions(), parent_.transportSocketOptions());
23:   real_host_description_ = data.host_description_;
24:   connection_ = std::move(data.connection_);
25:   connection_->addConnectionCallbacks(*this);
26:   read_filter_handle_ = std::make_shared<ConnReadFilter>(*this);
27:   connection_->addReadFilter(read_filter_handle_);
28:   Upstream::ClusterTrafficStats& cluster_traffic_stats = *host->cluster().trafficStats();
29:   connection_->setConnectionStats({cluster_traffic_stats.upstream_cx_rx_bytes_total_,
30:                                    cluster_traffic_stats.upstream_cx_rx_bytes_buffered_,
31:                                    cluster_traffic_stats.upstream_cx_tx_bytes_total_,
32:                                    cluster_traffic_stats.upstream_cx_tx_bytes_buffered_,
33:                                    &cluster_traffic_stats.bind_errors_, nullptr});
34:   connection_->noDelay(true);
35:   connection_->connect();
36: 
37:   if (idle_timeout_.has_value()) {
38:     idle_timer_ = connection_->dispatcher().createTimer([this]() -> void { onIdleTimeout(); });
39:     setIdleTimer();
40:   }
41: }
42: 
43: ActiveTcpClient::~ActiveTcpClient() {
44:   // Handle the case where deferred delete results in the ActiveClient being destroyed before
45:   // TcpConnectionData. Make sure the TcpConnectionData will not refer to this ActiveTcpClient
46:   // and handle clean up normally done in clearCallbacks()
47:   if (tcp_connection_data_) {
48:     ASSERT(state() == ActiveClient::State::Closed);
49:     tcp_connection_data_->release();
50:     parent_.onStreamClosed(*this, true);
51:     parent_.checkForIdleAndCloseIdleConnsIfDraining();
52:   }
53: }
54: 
55: // Undo the readDisable done in onEvent(Connected) - now that there is an associated connection,
56: // drain any data.
57: void ActiveTcpClient::readEnableIfNew() {
58:   // It is expected for Envoy use of ActiveTcpClient this function only be
59:   // called once. Other users of the TcpConnPool may recycle Tcp connections,
60:   // and this safeguards them against read-enabling too many times.
61:   if (!associated_before_) {
62:     associated_before_ = true;
63:     connection_->readDisable(false);
64:     // Also while we're at it, make sure the connection will proxy all TCP
65:     // data before picking up a FIN.
66:     connection_->detectEarlyCloseWhenReadDisabled(false);
67:   }
68: }
69: 
70: void ActiveTcpClient::close(Network::ConnectionCloseType type, absl::string_view details) {
71:   connection_->close(type, details);
72: }
73: 
74: void ActiveTcpClient::clearCallbacks() {
75:   if (state() == Envoy::ConnectionPool::ActiveClient::State::Busy && parent_.hasPendingStreams()) {
76:     auto* pool = &parent_;
77:     pool->scheduleOnUpstreamReady();
78:   }
79:   callbacks_ = nullptr;
80:   tcp_connection_data_ = nullptr;
81:   parent_.onStreamClosed(*this, true);
82:   setIdleTimer();
83:   parent_.checkForIdleAndCloseIdleConnsIfDraining();
84: }
