86: void ActiveTcpClient::onEvent(Network::ConnectionEvent event) {
87:   // If this is a newly established TCP connection, readDisable. This is to handle a race condition
88:   // for TCP for protocols like MySQL where the upstream writes first, and the data needs to be
89:   // preserved until a downstream connection is associated.
90:   // This is also necessary for prefetch to be used with such protocols.
